import re

with open('/tmp/alb-data/ALB-109.txt', 'r') as f:
    content = f.read()

# Find all [USER]: Round N: positions
user_pattern = re.compile(r'\[USER\]: Round (\d+):')
user_matches = list(user_pattern.finditer(content))

# Find all [TOOL RESULT] positions
tool_pattern = re.compile(r'\[TOOL RESULT\]:')
tool_matches = list(tool_pattern.finditer(content))

# For each round, find the tool result just before its header
def find_tool_result_before(round_num):
    # Find the user header for this round
    for m in user_matches:
        if int(m.group(1)) == round_num:
            user_pos = m.start()
            # Find the nearest tool result before this position
            nearest = None
            for tm in tool_matches:
                if tm.start() < user_pos:
                    nearest = tm
                else:
                    break
            if nearest:
                return nearest.start(), user_pos
    return None, None

def extract_json_from_tool_result(content, start_pos):
    # Skip "[TOOL RESULT]: " prefix
    json_start = content.index('{', start_pos)
    # Brace depth counting
    depth = 0
    in_string = False
    escape = False
    for i in range(json_start, len(content)):
        c = content[i]
        if escape:
            escape = False
            continue
        if c == '\\':
            escape = True
            continue
        if c == '"':
            in_string = not in_string
            continue
        if in_string:
            continue
        if c == '{':
            depth += 1
        elif c == '}':
            depth -= 1
            if depth == 0:
                return content[json_start:i+1]
    return None

# Get tool result for round 6 and round 7
target = "Florges"
results = {}

for rnd in [6, 7]:
    tool_start, user_pos = find_tool_result_before(rnd)
    if tool_start is None:
        print(f"Round {rnd}: no tool result found")
        continue
    json_str = extract_json_from_tool_result(content, tool_start)
    if json_str is None:
        print(f"Round {rnd}: no JSON found")
        continue

    # Check both formats
    has_intersection = f'"intersection"' in json_str
    has_per_section = f'"per_section"' in json_str

    found = False
    if has_intersection:
        # Parse simple intersection
        import json
        try:
            data = json.loads(json_str)
            if target in data.get('intersection', []):
                found = True
        except:
            pass
    elif has_per_section:
        import json
        try:
            data = json.loads(json_str)
            for section in data.get('per_section', []):
                if target in section.get('candidates', []):
                    found = True
                    break
        except:
            pass

    results[rnd] = found
    print(f"Round {rnd}: target '{target}' appears = {found}")

# Answer
if results.get(6) and results.get(7):
    print("True")
elif results.get(6) is False or results.get(7) is False:
    print("False")
else:
    print("Could not determine")

